import { describe, test, expect, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, rmSync, existsSync, readFileSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import { execSync } from 'node:child_process';
import {
  TEST_COMMAND_RE,
  GIT_COMMIT_RE,
  getStatePath,
  recordTestRun,
  readLastTestRun,
  preCommitTestGate,
} from '../../../pretool/bash/pre-commit-test-gate.js';
import { NOOP_CTX } from '../../../lib/context.js';

describe('pre-commit-test-gate', () => {
  describe('TEST_COMMAND_RE', () => {
    test.each([
      ['npm test', true],
      ['npm run test -- --watch', true],
      ['npx vitest run', true],
      ['pytest tests/', true],
      ['bun test', true],
      ['cd backend && pytest', true],
      ['ls tests/', false],
    ])('%s → %s', (cmd, expected) => {
      expect(TEST_COMMAND_RE.test(cmd)).toBe(expected);
    });

    // Known edge: "grep pytest" false-positives as a test run because \s before
    // pytest satisfies the separator class. Impact is bounded — just records a
    // redundant timestamp. Worth the simpler regex vs. a shell parser.
    test('known limitation: grep pytest false-positives', () => {
      expect(TEST_COMMAND_RE.test('grep pytest')).toBe(true);
    });
  });

  describe('GIT_COMMIT_RE', () => {
    test.each([
      ['git commit -m "x"', true],
      ['cd foo && git commit', true],
      ['git status', false],
      ['echo git commit', true], // matches on whitespace boundary — intentional, commits echoed are rare
    ])('%s → %s', (cmd, expected) => {
      expect(GIT_COMMIT_RE.test(cmd)).toBe(expected);
    });
  });

  describe('state file roundtrip', () => {
    let tmp: string;
    beforeEach(() => { tmp = mkdtempSync(join(tmpdir(), 'pctg-')); });
    afterEach(() => { rmSync(tmp, { recursive: true, force: true }); });

    test('recordTestRun writes JSON, readLastTestRun recovers it', () => {
      recordTestRun(tmp, 'npm test');
      const state = readLastTestRun(tmp);
      expect(state?.command).toBe('npm test');
      expect(typeof state?.timestamp).toBe('number');
    });

    test('readLastTestRun returns null when no file', () => {
      expect(readLastTestRun(tmp)).toBeNull();
    });

    test('getStatePath points at .claude/state/last-test-run.json', () => {
      expect(getStatePath(tmp)).toBe(join(tmp, '.claude', 'state', 'last-test-run.json'));
    });
  });

  describe('preCommitTestGate hook', () => {
    let tmp: string;
    beforeEach(() => { tmp = mkdtempSync(join(tmpdir(), 'pctg-e2e-')); });
    afterEach(() => { rmSync(tmp, { recursive: true, force: true }); });

    test('silent for non-Bash tools', () => {
      const input = { tool_name: 'Write', session_id: 's', tool_input: { file_path: '/a' } } as never;
      expect(preCommitTestGate(input, { ...NOOP_CTX, projectDir: tmp }).hookSpecificOutput).toBeUndefined();
    });

    test('test-runner Bash command records timestamp', () => {
      const input = { tool_name: 'Bash', session_id: 's', tool_input: { command: 'npm test' } } as never;
      preCommitTestGate(input, { ...NOOP_CTX, projectDir: tmp });
      expect(existsSync(getStatePath(tmp))).toBe(true);
      const state = JSON.parse(readFileSync(getStatePath(tmp), 'utf8'));
      expect(state.command).toBe('npm test');
    });

    test('non-test, non-commit Bash command is silent', () => {
      const input = { tool_name: 'Bash', session_id: 's', tool_input: { command: 'ls' } } as never;
      const r = preCommitTestGate(input, { ...NOOP_CTX, projectDir: tmp });
      expect(r.hookSpecificOutput).toBeUndefined();
      expect(existsSync(getStatePath(tmp))).toBe(false);
    });

    // #2919: the "this session" advisory must key off the session that
    // actually ran the tests — another session's run must not satisfy it.
    test('records the running session id (#2919)', () => {
      const input = { tool_name: 'Bash', session_id: 'sess-A', tool_input: { command: 'npm test' } } as never;
      preCommitTestGate(input, { ...NOOP_CTX, projectDir: tmp, sessionId: 'sess-A' });
      const state = JSON.parse(readFileSync(getStatePath(tmp), 'utf8'));
      expect(state.session_id).toBe('sess-A');
    });

    test('another session\'s test run does not satisfy this session\'s gate (#2919)', () => {
      // Session A runs tests…
      recordTestRun(tmp, 'npm test', 'sess-A');
      // …session B commits a staged file: must be advised as if no run happened.
      execSync('git init -q && git config user.email t@t && git config user.name t', { cwd: tmp });
      writeFileSync(join(tmp, 'f.txt'), 'x');
      execSync('git add f.txt', { cwd: tmp });

      const input = { tool_name: 'Bash', session_id: 'sess-B', tool_input: { command: 'git commit -m x' } } as never;
      const r = preCommitTestGate(input, { ...NOOP_CTX, projectDir: tmp, sessionId: 'sess-B' });
      const ctxText = (r.hookSpecificOutput as { additionalContext?: string })?.additionalContext;
      // outputNotify reflows text, so match across possible line breaks.
      expect(ctxText).toMatch(/no test run has been\s+recorded this session/);
    });

    test('own session\'s fresh test run keeps the commit clean (#2919)', () => {
      execSync('git init -q && git config user.email t@t && git config user.name t', { cwd: tmp });
      writeFileSync(join(tmp, 'f.txt'), 'x');
      execSync('git add f.txt', { cwd: tmp });
      // Test run AFTER the file edit, same session → silent gate.
      recordTestRun(tmp, 'npm test', 'sess-A');

      const input = { tool_name: 'Bash', session_id: 'sess-A', tool_input: { command: 'git commit -m x' } } as never;
      const r = preCommitTestGate(input, { ...NOOP_CTX, projectDir: tmp, sessionId: 'sess-A' });
      expect(r.hookSpecificOutput).toBeUndefined();
    });
  });
});
